module RefModule(
    input reset,
    input clock,
    input ee,
    input ep,
    input hold,
    output veto
    );parameter NORMAL=2'b00;
parameter HOLDING=2'b01;
parameter ONLY_EE=2'b10;

reg [1:0] pipeline_reg;

assign veto = (pipeline_reg == ONLY_EE) & (~ee);

always @(posedge clock)
begin
	if(reset)
	begin
		pipeline_reg <= NORMAL;
	end else begin
		case(pipeline_reg)
			NORMAL:  if(hold) pipeline_reg <= HOLDING;
						else pipeline_reg <= NORMAL;

			HOLDING: if(hold)
							if(ep) pipeline_reg <= ONLY_EE;
							else pipeline_reg <= HOLDING;
						else
							pipeline_reg <= NORMAL;

			ONLY_EE: if(hold) pipeline_reg <= ONLY_EE;
						else if (ee)
							pipeline_reg <= NORMAL;
						else pipeline_reg <= ONLY_EE;
		endcase
	end
end

endmodule
